import { readdirSync, readFileSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { parseOperation } from './lib/operations.js';

export function generateIndex(opsDir) {
  const lines = [
    '# Operations Index',
    '',
    'Auto-generated by `core/scripts/regenerate-operations-index.js`. Do not edit by hand.',
    '',
    '## Resolution',
    '',
    'On session start, the AI scans BOTH `core/operations/` and `user-data/operations/`.',
    'If a file with the same name exists in both, the `user-data/` version takes precedence.',
    '',
    '## Operations',
    '',
  ];
  const files = readdirSync(opsDir)
    .filter(f => f.endsWith('.md') && f !== 'INDEX.md')
    .sort();
  for (const f of files) {
    const op = parseOperation(readFileSync(join(opsDir, f), 'utf-8'));
    const triggers = Array.isArray(op.triggers) ? op.triggers.map(t => `"${t}"`).join(', ') : '';
    lines.push(`### ${op.name || f.replace(/\.md$/, '')}`);
    lines.push('');
    lines.push(`File: \`core/operations/${f}\``);
    lines.push(`Triggers: ${triggers}`);
    lines.push(`Description: ${op.description || ''}`);
    lines.push('');
  }
  return lines.join('\n');
}

export function writeIndex(opsDir) {
  const out = generateIndex(opsDir);
  writeFileSync(join(opsDir, 'INDEX.md'), out + '\n');
}

if (import.meta.url === `file://${process.argv[1]}`) {
  writeIndex(fileURLToPath(new URL('../operations', import.meta.url)));
}
